#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,M=2e5+10,Inf=0x7fffffff;const LL INF=0x3f3f3f3f3f3f3f3fll;LL val[M],dis[N],res;
int head[N],des[M],nxt[M],cap[M],cgt=1,que[N*100],H,T,s,t,cdt,h2[N],a[N],n,W,idx[N][2];bool inq[N];
inline void ins(const int &x,const int &y,const int &c,const LL &v)
{
//	printf("%d %d %d %lld\n",x,y,c,v);
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;val[cgt]=v;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;val[cgt]=-v;
}
inline bool spfa()
{
	memset(dis,0x3f,(cdt+5)<<3);dis[que[H=T=0]=s]=0;
	while(H<=T)
	{
		int u=que[H++];inq[u]=false;grep(u,i)
		{
			int v=des[i];if(cap[i]&&dis[u]+val[i]<dis[v])
			{
				dis[v]=dis[u]+val[i];
				if(!inq[v])inq[que[++T]=v]=true;
			}
		}
	}
	return dis[t]!=INF;
}
inline LL dfs(const int &u=s,LL in=INF)
{
	if(u==t)return in;int out=0;inq[u]=true;for(int i=head[u];i;i=nxt[i])
	{
		int v=des[i];if(!inq[v]&&cap[i]&&dis[v]==dis[u]+val[i])
		{
			LL tmp=dfs(v,in<cap[i]?in:cap[i]);res+=tmp*val[i];
			cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
		}
	}
	if(!out)dis[u]=INF;inq[u]=false;return out;
}
inline LL dinic(){while(spfa())dfs();return res;}
int srt[N];inline void cdq(const int &l,const int &r)
{
	if(l==r)return;const int &mid=(l+r)>>1;cdq(l,mid);cdq(mid+1,r);
	int p=0;rep(l,r,i)srt[++p]=a[i];std::sort(srt+1,srt+p+1);p=std::unique(srt+1,srt+p+1)-srt-1;
	rep(2,p,i)ins(cdt+i-1,cdt+i,Inf,srt[i]-srt[i-1]),ins(cdt+i,cdt+i-1,Inf,srt[i]-srt[i-1]);
	rep(l,mid,i){int l(1),r(p),mid,res=p;while(l<=r)srt[mid=(l+r)>>1]<a[i]?l=mid+1:(r=mid-1,res=mid);ins(cdt+res,idx[i][1],1,0);}
	rep(mid+1,r,i){int l(1),r(p),mid,res=p;while(l<=r)srt[mid=(l+r)>>1]<a[i]?l=mid+1:(r=mid-1,res=mid);ins(idx[i][0],cdt+res,1,0);} cdt+=p;
}
int main()
{
	n=read();W=read();s=++cdt;t=++cdt;
	rep(1,n,i){a[i]=read();ins(s,idx[i][0]=++cdt,1,0);ins(cdt,t,1,W);ins(idx[i][1]=++cdt,t,1,0);}
	cdq(1,n);printf("%lld\n",dinic());return 0;
}
